// Calculate technical indicators for trading signals
const data = $input.item.json;

// Mock historical price data (in real scenario, fetch from database)
const historicalPrices = {
  'bitcoin': [42000, 42500, 41800, 43200, 43500, 42900, 43100, 43400],
  'ethereum': [2200, 2250, 2180, 2300, 2350, 2280, 2320, 2380],
  'AAPL': [150, 151, 149, 152, 153, 151, 152, 154],
  'GOOGL': [100, 101, 99, 102, 103, 101, 102, 104]
};

const currentPrice = data.price || 0;
const symbol = data.symbol || 'UNKNOWN';
const priceHistory = historicalPrices[symbol.toLowerCase()] || [currentPrice];

// Calculate Simple Moving Average (SMA)
const calculateSMA = (prices, period) => {
  if (prices.length < period) return null;
  const sum = prices.slice(-period).reduce((a, b) => a + b, 0);
  return sum / period;
};

// Calculate Exponential Moving Average (EMA)
const calculateEMA = (prices, period) => {
  if (prices.length < period) return null;
  const k = 2 / (period + 1);
  let ema = prices.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return ema;
};

// Calculate RSI (Relative Strength Index)
const calculateRSI = (prices, period = 14) => {
  if (prices.length < period + 1) return null;
  const deltas = [];
  for (let i = 1; i < prices.length; i++) {
    deltas.push(prices[i] - prices[i - 1]);
  }

  let gains = 0, losses = 0;
  for (let i = 0; i < period; i++) {
    if (deltas[i] > 0) gains += deltas[i];
    else losses -= deltas[i];
  }

  let avgGain = gains / period;
  let avgLoss = losses / period;

  for (let i = period; i < deltas.length; i++) {
    if (deltas[i] > 0) gains = deltas[i];
    else gains = 0;
    if (deltas[i] < 0) losses = -deltas[i];
    else losses = 0;
    avgGain = (avgGain * (period - 1) + gains) / period;
    avgLoss = (avgLoss * (period - 1) + losses) / period;
  }

  const rs = avgGain / (avgLoss || 1);
  return 100 - (100 / (1 + rs));
};

// Calculate MACD (Moving Average Convergence Divergence)
const calculateMACD = (prices) => {
  const ema12 = calculateEMA(prices, 12);
  const ema26 = calculateEMA(prices, 26);
  if (!ema12 || !ema26) return null;
  return { macd: ema12 - ema26, signal: (ema12 - ema26) * 0.7 };
};

// Calculate Bollinger Bands
const calculateBollingerBands = (prices, period = 20, stdDev = 2) => {
  if (prices.length < period) return null;
  const sma = calculateSMA(prices, period);
  const slice = prices.slice(-period);
  const variance = slice.reduce((sum, p) => sum + Math.pow(p - sma, 2), 0) / period;
  const stdev = Math.sqrt(variance);
  return {
    upper: sma + (stdev * stdDev),
    middle: sma,
    lower: sma - (stdev * stdDev)
  };
};

const sma50 = calculateSMA(priceHistory, 50) || calculateSMA(priceHistory, Math.min(priceHistory.length - 1, 50));
const sma200 = calculateSMA(priceHistory, 200) || calculateSMA(priceHistory, Math.min(priceHistory.length - 1, 200));
const ema12 = calculateEMA(priceHistory, 12) || calculateEMA(priceHistory, Math.min(priceHistory.length - 1, 12));
const rsi = calculateRSI(priceHistory) || 50;
const macd = calculateMACD(priceHistory) || { macd: 0, signal: 0 };
const bollingerBands = calculateBollingerBands(priceHistory) || { upper: currentPrice * 1.05, middle: currentPrice, lower: currentPrice * 0.95 };

const priceChange24h = data.change_24h || 0;
const volume24h = data.volume_24h || 0;
const marketCap = data.market_cap || 0;

return {
  json: {
    symbol: symbol,
    currentPrice: currentPrice,
    priceChange24h: priceChange24h,
    volume24h: volume24h,
    marketCap: marketCap,

    // Technical Indicators
    technicalIndicators: {
      sma50: sma50 ? parseFloat(sma50.toFixed(2)) : null,
      sma200: sma200 ? parseFloat(sma200.toFixed(2)) : null,
      ema12: ema12 ? parseFloat(ema12.toFixed(2)) : null,
      rsi: parseFloat(rsi.toFixed(2)),
      macd: parseFloat(macd.macd.toFixed(2)),
      macdSignal: parseFloat(macd.signal.toFixed(2)),
      bollingerUpper: parseFloat(bollingerBands.upper.toFixed(2)),
      bollingerMiddle: parseFloat(bollingerBands.middle.toFixed(2)),
      bollingerLower: parseFloat(bollingerBands.lower.toFixed(2))
    },

    // Trend Analysis
    trend: {
      shortTerm: currentPrice > sma50 ? 'BULLISH' : 'BEARISH',
      longTerm: sma50 > sma200 ? 'BULLISH' : 'BEARISH',
      rsiStatus: rsi > 70 ? 'OVERBOUGHT' : rsi < 30 ? 'OVERSOLD' : 'NEUTRAL',
      macdTrend: macd.macd > macd.signal ? 'BULLISH' : 'BEARISH'
    },

    // Timestamp
    timestamp: new Date().toISOString(),
    analysisDate: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })
  }
};

// Analyze AI signals and calculate confidence scores
const aiResponse = $input.item.json;
const signal = aiResponse.signal || 'HOLD';
const confidence = aiResponse.confidence || 0.5;
const reasoning = aiResponse.reasoning || 'Insufficient data';

// Thresholds
const buyThreshold = 0.65;
const sellThreshold = 0.65;
const holdConfidence = 0.5;

// Determine action based on confidence
let action = 'HOLD';
let actionConfidence = 0;
let riskLevel = 'MEDIUM';

if (signal === 'BUY' && confidence >= buyThreshold) {
  action = 'BUY';
  actionConfidence = confidence;
  riskLevel = confidence > 0.85 ? 'LOW' : 'MEDIUM';
} else if (signal === 'SELL' && confidence >= sellThreshold) {
  action = 'SELL';
  actionConfidence = confidence;
  riskLevel = confidence > 0.85 ? 'LOW' : 'MEDIUM';
} else {
  action = 'HOLD';
  actionConfidence = confidence;
  riskLevel = 'LOW';
}

// Recommended position size based on confidence
const positionSize = action === 'HOLD' ? 0 : Math.round(actionConfidence * 100);

// Alert level
let alertLevel = 'INFO';
if (action !== 'HOLD' && actionConfidence > 0.80) {
  alertLevel = 'CRITICAL';
} else if (action !== 'HOLD' && actionConfidence > 0.70) {
  alertLevel = 'HIGH';
} else if (action !== 'HOLD') {
  alertLevel = 'MEDIUM';
}

const timestamp = new Date().toISOString();
const signalId = `SIG-${new Date().getTime()}-${Math.random().toString(36).substr(2, 9)}`;

return {
  json: {
    signalId: signalId,
    symbol: aiResponse.symbol,
    currentPrice: aiResponse.currentPrice,
    action: action,
    confidence: parseFloat(actionConfidence.toFixed(4)),
    riskLevel: riskLevel,
    positionSize: positionSize,
    alertLevel: alertLevel,
    aiReasoning: reasoning,

    // Recommendation details
    recommendation: {
      action: action,
      entryPrice: aiResponse.currentPrice,
      targetPrice: action === 'BUY' ? aiResponse.currentPrice * 1.05 : action === 'SELL' ? aiResponse.currentPrice * 0.95 : aiResponse.currentPrice,
      stopLoss: action === 'BUY' ? aiResponse.currentPrice * 0.98 : action === 'SELL' ? aiResponse.currentPrice * 1.02 : aiResponse.currentPrice,
      profitTarget: action === 'BUY' ? aiResponse.currentPrice * 1.10 : action === 'SELL' ? aiResponse.currentPrice * 0.90 : aiResponse.currentPrice,
      timeframe: '15m-1h'
    },

    // Validation flags
    isValidSignal: action !== 'HOLD',
    shouldAlert: action !== 'HOLD' && actionConfidence >= holdConfidence,
    shouldExecute: action !== 'HOLD' && actionConfidence >= 0.75,

    timestamp: timestamp,
    originalAIResponse: aiResponse
  }
};

// Generate formatted trading alert message
const signal = $input.item.json;
const action = signal.action;
const emoji = action === 'BUY' ? '📈' : action === 'SELL' ? '📉' : '⏸️';

const slackMessage = `${emoji} *TRADING ALERT — ${action}*\n\n` +
  `*Symbol:* ${signal.symbol}\n` +
  `*Action:* ${action}\n` +
  `*Confidence:* ${(signal.confidence * 100).toFixed(1)}%\n` +
  `*Current Price:* \$${signal.currentPrice.toFixed(2)}\n\n` +
  `*Recommendations:*\n` +
  `Entry: \$${signal.recommendation.entryPrice.toFixed(2)}\n` +
  `Target: \$${signal.recommendation.targetPrice.toFixed(2)}\n` +
  `Stop Loss: \$${signal.recommendation.stopLoss.toFixed(2)}\n` +
  `Take Profit: \$${signal.recommendation.profitTarget.toFixed(2)}\n\n` +
  `*Position Size:* ${signal.positionSize}%\n` +
  `*Risk Level:* ${signal.riskLevel}\n` +
  `*Signal ID:* ${signal.signalId}\n` +
  `*AI Reasoning:* ${signal.aiReasoning}\n\n` +
  `*Timeframe:* ${signal.recommendation.timeframe}`;

const emailSubject = `🚀 ${emoji} Trading Alert: ${action} ${signal.symbol} @ ${signal.currentPrice} - ${(signal.confidence * 100).toFixed(1)}% Confidence`;

const emailBody = `
<h2>${emoji} Trading Alert - ${action} Signal</h2>
<p><strong>Symbol:</strong> ${signal.symbol}</p>
<p><strong>Action:</strong> ${action}</p>
<p><strong>Confidence:</strong> ${(signal.confidence * 100).toFixed(1)}%</p>
<p><strong>Current Price:</strong> $${signal.currentPrice.toFixed(2)}</p>

<h3>📊 Recommendations</h3>
<ul>
  <li>Entry Price: $${signal.recommendation.entryPrice.toFixed(2)}</li>
  <li>Target Price: $${signal.recommendation.targetPrice.toFixed(2)}</li>
  <li>Stop Loss: $${signal.recommendation.stopLoss.toFixed(2)}</li>
  <li>Take Profit: $${signal.recommendation.profitTarget.toFixed(2)}</li>
  <li>Position Size: ${signal.positionSize}%</li>
  <li>Risk Level: ${signal.riskLevel}</li>
  <li>Timeframe: ${signal.recommendation.timeframe}</li>
</ul>

<h3>🤖 AI Analysis</h3>
<p>${signal.aiReasoning}</p>

<p><strong>Signal ID:</strong> ${signal.signalId}</p>
<p><strong>Generated:</strong> ${signal.timestamp}</p>
`;

const smsMessage = `${emoji} ${action} ${signal.symbol} @ $${signal.currentPrice.toFixed(2)} - Confidence: ${(signal.confidence * 100).toFixed(1)}% - ID: ${signal.signalId}`;

return {
  json: {
    ...signal,
    alertMessages: {
      slack: slackMessage,
      email: {
        subject: emailSubject,
        body: emailBody
      },
      sms: smsMessage
    }
  }
};

// Log successful trade signal execution
const timestamp = new Date().toISOString();
const signal = $input.item.json;

console.log(`✅ TRADE SIGNAL EXECUTED: ${signal.signalId} | ${signal.action} ${signal.symbol} @ $${signal.currentPrice} | Confidence: ${(signal.confidence * 100).toFixed(1)}% | Risk: ${signal.riskLevel} | Time: ${timestamp}`);

// Cumulative statistics
const stats = $getWorkflowStaticData('global').stats || {
  totalSignals: 0,
  buySignals: 0,
  sellSignals: 0,
  totalAlerts: 0,
  lastSignal: null,
  averageConfidence: 0
};

if (signal.action === 'BUY') stats.buySignals++;
else if (signal.action === 'SELL') stats.sellSignals++;
stats.totalSignals++;
stats.totalAlerts++;
stats.lastSignal = timestamp;
stats.averageConfidence = (stats.averageConfidence + signal.confidence) / 2;

$getWorkflowStaticData('global').stats = stats;

return {
  json: {
    success: true,
    signalId: signal.signalId,
    action: signal.action,
    symbol: signal.symbol,
    currentPrice: signal.currentPrice,
    confidence: signal.confidence,
    timestamp: timestamp,
    cumulativeStats: stats,
    alertsSent: {
      slack: true,
      email: true,
      sms: true
    }
  }
};
